        private static TierPlan PhysicalWithReplace(IDictionary<string, string> replacements)
        {
            var plan = PhysicalDefault();
            foreach (var kv in replacements)
            {
                switch (kv.Key)
                {
                    case "T4": plan.T4 = TierState.Replace; plan.T4Rows = RowsForSet(kv.Value); break;
                    case "T5": plan.T5 = TierState.Replace; plan.T5Rows = RowsForSet(kv.Value); break;
                    case "T6": plan.T6 = TierState.Replace; plan.T6Rows = RowsForSet(kv.Value); break;
                    case "T7": plan.T7 = TierState.Replace; plan.T7Rows = RowsForSet(kv.Value); break;
                    case "T8": plan.T8 = TierState.Replace; plan.T8Rows = RowsForSet(kv.Value); break;
                    case "T9": plan.T9 = TierState.Replace; plan.T9Rows = RowsForSet(kv.Value); break;
                    case "T10": plan.T10 = TierState.Replace; plan.T10Rows = RowsForSet(kv.Value); break;
                }
            }
            return plan;
        }

