        private static Dictionary<string, TierPlan> BuildCategoryMap()
        {
            // Category fallback for the spatial/annotation classes. Physical families
            // have too many category-specific REPLACE rules to safely key on category,
            // so they fall through to DefaultPlan when family-name lookup misses.
            var d = new Dictionary<string, TierPlan>();
            d["Analytical Links"] = Spatial();
            d["Analytical Members"] = Spatial();
            d["Analytical Nodes"] = Spatial();
            d["Analytical Openings"] = Spatial();
            d["Analytical Panels"] = Spatial();
            d["Area Loads"] = Spatial();
            d["Areas"] = Spatial();
            d["Assemblies"] = Spatial();
            d["Internal Area Loads"] = Spatial();
            d["Internal Line Loads"] = Spatial();
            d["Internal Point Loads"] = Spatial();
            d["Line Loads"] = Spatial();
            d["Model Groups"] = Spatial();
            d["Parts"] = Spatial();
            d["Point Loads"] = Spatial();
            d["Property Line Segments"] = Spatial();
            d["Property Lines"] = Spatial();
            d["RVT Links"] = Spatial();
            d["Rooms"] = Spatial();
            d["Spaces (MEP)"] = Spatial();
            d["Toposolid Links"] = Spatial();
            d["Zones (HVAC)"] = Spatial();
            d["Sheets (ViewSheet)"] = Annotation();
            d["Sheets — Architectural discipline"] = Annotation();
            d["Sheets — MEP disciplines (M/E/P/FP/LV)"] = Annotation();
            d["Sheets — Structural discipline"] = Annotation();
            return d;
        }
    }
